import hashlib
import os
import subprocess
import sys
from pathlib import Path

AC_UID = "30920553790455f5"
AC_TYPE = "data"

SCRIPT = str(Path(__file__).parent.parent.parent.parent / "scripts" / "execute-push.py")
REPO_ROOT = str(Path(__file__).parent.parent.parent.parent)


def _compute_repo_hash() -> str:
    real_root = os.path.realpath(REPO_ROOT)
    return hashlib.sha256(real_root.encode()).hexdigest()[:16]


def test_AC2():
    """
    GIVEN: CLAUDE_SESSION_ID=testsid is set and no grant file exists at the computed path
    WHEN:  python3 scripts/execute-push.py --request-id abc123 --repo-hash $(printf '%s' "$(realpath "$(git rev-parse --show-toplevel)")") | sha256sum | cut -c1-16) --remote origin is run from the repo root
    THEN:  exit code is 1 and stderr contains "push-analyst did not write a grant"
    """
    repo_hash = _compute_repo_hash()
    env = {**os.environ, "CLAUDE_SESSION_ID": "testsid"}
    # Remove any pre-existing grant to ensure clean state
    result = subprocess.run(
        [sys.executable, SCRIPT,
         "--request-id", "abc123",
         "--repo-hash", repo_hash,
         "--remote", "origin"],
        capture_output=True,
        text=True,
        env=env,
        cwd=REPO_ROOT,
    )
    assert result.returncode == 1, f"Expected exit 1, got {result.returncode}. stderr: {result.stderr}"
    assert "push-analyst did not write a grant" in result.stderr, (
        f"Expected 'push-analyst did not write a grant' in stderr, got: {result.stderr}"
    )
